#include <iostream>
#include <string>
#include <string_view>

class Person
{
    std::string m_name;
    int m_age{};

public:
    Person(std::string_view name, int age)
        : m_name{ name }, m_age{ age }
    {
    }

    std::string_view getName() const { return m_name; }
    int getAge() const { return m_age; }
};

class Student : public Person
{
    int m_studentId{};

public:
    Student(std::string_view name, int age, int studentId)
        : Person{ name, age }, m_studentId{ studentId }
    {
    }

    int getStudentId() const { return m_studentId; }
};

int main()
{
    std::string name{};
    int age{};
    std::cin >> name >> age;

    int studentId{};
    std::cin >> studentId;

    Student s{ name, age, studentId };
    std::cout << "Name: " << s.getName() << '\n';
    std::cout << "Age: " << s.getAge() << '\n';
    std::cout << "Student ID: " << s.getStudentId() << '\n';

    return 0;
}

